from beeai_framework.agents.react.events import (
    ReActAgentStartEvent,
    ReActAgentToolCallEvent,
    ReActAgentToolResultEvent,
    ReActAgentSuccessEvent,
    ReActAgentErrorEvent,
    ReActAgentIterationEvent
)
from beeai_framework.emitter import EventMeta
from vex_sdk import VexTrace, VexSpan, VexPolicy
import time

class VexBeeAIListener:
    def __init__(self, vex_client: VexClient, policies: list[VexPolicy] = None):
        self.vex = vex_client
        self.policies = policies or [
            VexPolicy.MEMORY_BOUNDS_CHECK,
            VexPolicy.TOOL_INPUT_VALIDATION,
            VexPolicy.OUTPUT_FORMAT_VALIDATION,
            VexPolicy.INJECTION_DETECTION
        ]
        self._active_traces: dict[str, VexTrace] = {}

    def on_start(self, data: ReActAgentStartEvent, meta: EventMeta):
        trace = self.vex.start_trace(
            trace_id=meta.run_id,
            agent_type="ReActAgent",
            framework="beeai",
            input_text=data.input.text if hasattr(data.input, 'text') else str(data.input),
            metadata={"model": "granite-13b-chat-v2", "timestamp": time.time()}
        )
        self._active_traces[meta.run_id] = trace
        # Validate memory bounds before agent starts reasoning
        memory_check = self.vex.check_policy(
            VexPolicy.MEMORY_BOUNDS_CHECK,
            context={"memory_size": data.memory.messages.__len__() if hasattr(data, 'memory') else 0}
        )
        if memory_check.violated:
            raise RuntimeError(f"Vex memory policy violated: {memory_check.reason}")

    def on_tool_call(self, data: ReActAgentToolCallEvent, meta: EventMeta):
        trace = self._active_traces.get(meta.run_id)
        if trace:
            span = trace.start_span(
                name=f"tool_call:{data.tool_name}",
                span_type="tool",
                input_data={"tool": data.tool_name, "input": data.tool_input}
            )
            # Validate tool input for injection patterns
            injection_check = self.vex.check_policy(
                VexPolicy.INJECTION_DETECTION,
                context={"tool_name": data.tool_name, "tool_input": str(data.tool_input)}
            )
            if injection_check.violated:
                span.flag_anomaly("injection_detected", injection_check.reason)
                raise ValueError(f"Vex blocked tool call: potential injection in {data.tool_name}")
            trace.set_active_span(span)

    def on_tool_result(self, data: ReActAgentToolResultEvent, meta: EventMeta):
        trace = self._active_traces.get(meta.run_id)
        if trace and trace.active_span:
            trace.active_span.finish(
                output_data={"result": str(data.tool_result)[:2000]},  # Cap logged output
                success=not data.error
            )
            if data.error:
                trace.active_span.flag_anomaly("tool_error", str(data.error))

    def on_success(self, data: ReActAgentSuccessEvent, meta: EventMeta):
        trace = self._active_traces.pop(meta.run_id, None)
        if trace:
            # Validate Granite output format before returning to caller
            format_check = self.vex.check_policy(
                VexPolicy.OUTPUT_FORMAT_VALIDATION,
                context={"output": data.output.text, "expected_format": "natural_language"}
            )
            trace.finish(
                output_text=data.output.text,
                success=True,
                anomalies=[format_check.reason] if format_check.violated else []
            )

    def on_error(self, data: ReActAgentErrorEvent, meta: EventMeta):
        trace = self._active_traces.pop(meta.run_id, None)
        if trace:
            trace.finish(
                success=False,
                error=str(data.error),
                error_type=type(data.error).__name__
            )
            self.vex.report_failure(
                trace_id=meta.run_id,
                failure_type="agent_error",
                details={"error": str(data.error), "framework": "beeai"}
            )

    def on_iteration(self, data: ReActAgentIterationEvent, meta: EventMeta):
        # Circuit-break runaway agents exceeding max iterations
        if data.iteration > 15:
            self.vex.trigger_circuit_breaker(
                trace_id=meta.run_id,
                reason=f"Agent exceeded 15 iterations (current: {data.iteration})"
            )
            raise RuntimeError("Vex circuit breaker: agent iteration limit exceeded")
